    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* Channel Sidebar */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
    overflow-y: auto;
}

.sidebar-title {
    padding: 16px 16px 8px;
    font-size: 1rem;
    color: #fff;
    margin: 0;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.channel-item {
    padding: 10px 16px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #2c2f33;
}

.channel-item.active {
    background: #2c2f33;
    border-left-color: #4a9eff;
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    color: #fff;
}

.unread-badge {
    background: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: bold;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    display: block;
    font-size: 0.75rem;
    color: #888;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* Main Message Area */
.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
}

.message-area.thread-open {
    max-width: 55%;
}

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fafafa;
}

.message-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #1a1d21;
}

.message-header p {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #666;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.load-more-btn {
    align-self: center;
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 4px;
    padding: 6px 16px;
    cursor: pointer;
    font-size: 0.8rem;
    color: #555;
    margin-bottom: 12px;
}

.load-more-btn:hover:not(:disabled) {
    background: #e0e0e0;
}

.message-bubble {
    position: relative;
    padding: 8px 12px;
    border-radius: 6px;
    transition: background 0.1s;
}

.message-bubble:hover {
    background: #f5f5f5;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #1a1d21;
}

.message-time {
    font-size: 0.7rem;
    color: #999;
}

.message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #f0f4ff;
    border: 1px solid #d0d8e8;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.75rem;
    cursor: pointer;
    transition: background 0.1s;
}

.reaction-badge:hover {
    background: #dce6ff;
}

.thread-link {
    background: none;
    border: none;
    color: #4a9eff;
    font-size: 0.78rem;
    cursor: pointer;
    padding: 4px 0 0;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 0.75rem;
    padding: 4px 8px;
    border-radius: 4px;
    color: #555;
}

.action-btn:hover {
    background: #f0f0f0;
}

