    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    margin-top: 4px;
    width: fit-content;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

/* Message Input */
.message-input-area {
    display: flex;
