+    color: #333;
+    line-height: 1.4;
+    white-space: pre-wrap;
+    word-break: break-word;
+}
+
+.reaction-row {
+    display: flex;
+    flex-wrap: wrap;
+    gap: 4px;
+    margin-top: 6px;
+}
+
+.reaction-badge {
+    display: inline-flex;
+    align-items: center;
+    gap: 3px;
+    background: #f0f4ff;
+    border: 1px solid #d0d8e8;
+    border-radius: 12px;
+    padding: 2px 8px;
+    font-size: 0.75rem;
+    cursor: pointer;
+    transition: background 0.1s;
+}
+
+.reaction-badge:hover {
+    background: #dce6ff;
+}
+
+.thread-link {
+    background: none;
+    border: none;
+    color: #4a9eff;
+    font-size: 0.78rem;
+    cursor: pointer;
+    padding: 4px 0 0;
+    font-weight: 500;
+}
+
+.thread-link:hover {
+    text-decoration: underline;
+}
+
+.message-actions {
+    position: absolute;
+    top: 4px;
+    right: 8px;
+    display: flex;
+    gap: 4px;
+    background: #fff;
+    border: 1px solid #e0e0e0;
+    border-radius: 6px;
+    padding: 2px 4px;
+    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
+}
+
+.action-btn {
+    background: none;
+    border: none;
+    cursor: pointer;
+    font-size: 0.75rem;
+    padding: 4px 8px;
+    border-radius: 4px;
+    color: #555;
+}
+
+.action-btn:hover {
+    background: #f0f0f0;
+}
+
+.emoji-picker {
+    display: flex;
+    gap: 4px;
+    padding: 6px;
+    background: #fff;
+    border: 1px solid #e0e0e0;
+    border-radius: 8px;
+    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
+    margin-top: 4px;
+    width: fit-content;
+}
+
+.emoji-btn {
+    background: none;
+    border: none;
+    font-size: 1.2rem;
+    cursor: pointer;
+    padding: 4px 6px;
+    border-radius: 4px;
+}
+
+.emoji-btn:hover {
+    background: #f0f0f0;
+}
+
+/* Message Input */
+.message-input-area {
+    display: flex;
+    align-items: flex-end;
+    gap: 8px;
+    padding: 12px 20px;
+    border-top: 1px solid #e0e0e0;
+    background: #fafafa;
+}
+
+.message-input-area textarea {
+    flex: 1;
+    resize: none;
+    border: 1px solid #ddd;
+    border-radius: 6px;
+    padding: 10px 12px;
+    font-size: 0.9rem;
+    font-family: inherit;
+    outline: none;
+    transition: border-color 0.15s;
+}
+
+.message-input-area textarea:focus {
+    border-color: #4a9eff;
+}
+
+.send-btn {
+    background: #4a9eff;
+    color: #fff;
+    border: none;
+    border-radius: 6px;
+    padding: 10px 20px;
+    font-size: 0.85rem;
+    font-weight: 600;
+    cursor: pointer;
+    transition: background 0.15s;
+}
+
+.send-btn:hover:not(:disabled) {
+    background: #3580d4;
+}
+
+.send-btn:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* No Channel Selected */
+.no-channel-selected {
+    flex: 1;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    color: #999;
+    font-size: 1rem;
+}
+
+/* Thread Panel */
+.thread-panel {
+    width: 25%;
+    min-width: 280px;
+    border-left: 1px solid #e0e0e0;
+    display: flex;
+    flex-direction: column;
+    background: #fafafa;
+}
+
+.thread-header {
+    display: flex;
+    align-items: center;
+    justify-content: space-between;
+    padding: 12px 16px;
+    border-bottom: 1px solid #e0e0e0;
+    background: #fff;
+}
+
+.thread-header h3 {
+    margin: 0;
+    font-size: 1rem;
+}
+
+.close-thread-btn {
+    background: none;
+    border: none;
+    font-size: 1.4rem;
+    cursor: pointer;
+    color: #666;
+    padding: 0 4px;
+    line-height: 1;
+}
+
+.close-thread-btn:hover {
+    color: #333;
+}
+
+.thread-root-message {
+    padding: 12px 16px;
+    background: #f0f4ff;
+    border-bottom: 1px solid #e0e0e0;
+    font-size: 0.85rem;
+}
+
+.thread-root-message .message-author {
+    font-size: 0.8rem;
+}
+
+.thread-root-message p {
+    margin: 4px 0 0;
+    color: #444;
+    line-height: 1.3;
+}
+
+.thread-replies {
+    flex: 1;
+    overflow-y: auto;
+    padding: 12px 16px;
+    display: flex;
+    flex-direction: column;
+    gap: 4px;
+}
+
+.thread-reply {
+    padding: 6px 10px;
+}
+

